    is_prime[0] = false;
    is_prime[1] = false;
    for (let p = 2; p * p <= MAX_VAL; p++) {
        if (is_prime[p]) {
            for (let i = p * p; i <= MAX_VAL; i += p)
                is_prime[i] = false;
        }
    }
}

sieve(); // Initialize the sieve once

/**
 * Finds the smallest prime number P such that P >= start.
 * Assumes start >= 1.
 * @param {number} start 
 * @returns {number}
 */
function findNextPrime(start) {
    let p = Math.max(2, start);
    while (p <= MAX_VAL) {
        if (is_prime[p]) {
            return p;
        }
        p++;
    }
    // Should not happen given constraints and MAX_VAL setup
    throw new Error("Prime not found within bounds.");
}

