 * Finds the smallest non-prime number NP such that NP >= start.
 * Assumes start >= 1.
 * @param {number} start 
 * @returns {number}
 */
function findNextNonPrime(start) {
    let np = start;
    while (np <= MAX_VAL) {
        // 1 is non-prime.
        if (np === 1) return 1;
        // Composite numbers (non-prime numbers > 1) are those where is_prime[np] is false.
        if (!is_prime[np]) {
            return np;
        }
        np++;
    }
    // Should not happen given constraints and MAX_VAL setup
    throw new Error("Non-prime not found within bounds.");
}


